    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// Aw b蓻 s蓻b蓻n kelen kelen b蓻蓻 kalan ka b蓴 a k蓴n蓴    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Ka sira dafalen dilan        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// Aw b蓻 kunkan s蓻b蓻n        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// Kunnafoniw        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


